    await user.tab()
    expect(screen.getByRole("button", { name: "Before" })).toHaveFocus()
    await user.tab()
    expect(screen.getByRole("button", { name: "Expand sidebar" })).toHaveFocus()
    expect(screen.getByRole("button", { name: "Hidden item", hidden: true })).not.toHaveFocus()
