    const trigger = screen.getByRole("button", { name: "Collapse sidebar" })

    await userEvent.click(trigger)
    expect(onStateChange).toHaveBeenCalledWith("rail")
    expect(trigger).toHaveAttribute("aria-expanded", "true")
